def normalize_path(raw_path: str) -> str:
    """Normalize request path to a known route template to prevent cardinality explosion.
    
    Instead of using raw paths like /api/v1/users/12345/profile (infinite cardinality),
    we map to templates like /api/v{version}/users/{user_id}/profile (bounded cardinality).
    """
